import {
  BN_GOVERNANCE_DEFAULT_CONFIG,
  BnGovernanceConfig,
  BnGovernanceFinding,
  BnGovernanceMapping,
  BnGovernanceOutboundResult,
  BnGovernanceRestoreOptions,
  BnGovernanceResult,
} from '@binom/sdk-governance/types';
import {
  appendGovernanceRules,
  buildOutboundUserMessage,
  detect,
  mask,
  restore,
  sanitize,
} from '@binom/sdk-governance/core';
import { mergeConfig } from '@binom/sdk-governance/detectors';

export class BnGovernanceSanitizerSvc {
  private config: BnGovernanceConfig;

  constructor(defaultConfig?: Partial<BnGovernanceConfig>) {
    this.config = mergeConfig(BN_GOVERNANCE_DEFAULT_CONFIG, defaultConfig);
  }

  detect(input: string, config?: Partial<BnGovernanceConfig>): BnGovernanceFinding[] {
    return detect(input, this.mergeRuntimeConfig(config));
  }

  sanitize(input: string, config?: Partial<BnGovernanceConfig>): BnGovernanceResult {
    return sanitize(input, this.mergeRuntimeConfig(config));
  }

  appendGovernanceRules(sanitized: string, rules: string): string {
    return appendGovernanceRules(sanitized, rules);
  }

  buildOutboundUserMessage(
    input: string,
    rules: string,
    config?: Partial<BnGovernanceConfig>,
  ): BnGovernanceOutboundResult {
    return buildOutboundUserMessage(input, rules, this.mergeRuntimeConfig(config));
  }

  mask(input: string, config?: Partial<BnGovernanceConfig>): BnGovernanceResult {
    return mask(input, this.mergeRuntimeConfig(config));
  }

  restore(
    input: string,
    mappingOrId: BnGovernanceMapping | string,
    options?: BnGovernanceRestoreOptions,
  ): string {
    return restore(input, mappingOrId, options);
  }

  updateConfig(config: Partial<BnGovernanceConfig>): void {
    this.config = mergeConfig(this.config, config);
  }

  getConfig(): BnGovernanceConfig {
    return { ...this.config, detectors: { ...this.config.detectors } };
  }

  private mergeRuntimeConfig(config?: Partial<BnGovernanceConfig>): BnGovernanceConfig {
    return mergeConfig(this.config, config);
  }
}
